const sums = items.summaries || [];
const base = $input.all()[0]?.json || {};

const combined = sums.map((s, i) => {
  const c = s?.choices?.[0]?.message?.content || s?.message?.content || '';
  return `Bölüm ${i+1}:\n${c}`;
}).join('\n\n---\n\n');

return [{ json: { ...base, combinedSummary: combined } }];

