let p;
try { p = JSON.parse(m[0]); }
catch(e) { try { p = JSON.parse(m[0].replace(/,\s*}/g,'}').replace(/,\s*]/g,']')); } catch(e2) { return [{ json: { error: true, output: 'JSON hatası: '+e2.message, ...base }}]; }
}

const kavramlar = (p.anahtar_kavramlar||[]).map(k=>`\`${k}\``).join(' · ');
