const data = $input.first().json;
const answer = data?.choices?.[0]?.message?.content || data?.message?.content || 'Cevap üretilemedi.';
const prev = $('Message Analyze').first().json;
return [{ json: { ...prev, output: answer }}];

const data = $input.first().json;
const tests = data.lastTests || [];
const answer = (data.msg || '').trim().toUpperCase().charAt(0);

if (!tests.length) return [{ json: { ...data, output: '❌ Aktif test bulunamadı. Önce bir video analizi yapın.' }}];

let result = '';
let correct = 0;

tests.forEach((q, i) => {
  const userAns = answer; // Basit: tek harf gönderdiyse ilk soruyu kontrol et
  const isCorrect = q.dogru_cevap === userAns;
  if (isCorrect) correct++;
  result += `*Soru ${i+1}:* ${isCorrect ? '✅ Doğru' : '❌ Yanlış'}\nCevabın: ${userAns} | Doğru: ${q.dogru_cevap}\n${q.aciklama}\n\n`;
});

return [{ json: { ...data, output: `*Test Değerlendirmesi*\n\n${result}Puan: ${correct}/${tests.length}` }}];

const d = $input.first().json;
const helpMsg = `👋 *YouTube AI Master*

• YouTube linki → Ders planı + test
• Soru sor → Son videoyla ilgili cevap veririm
• A/B/C/D → Test cevabını kontrol ederim
• /history → Geçmişin

Örnek: https://youtube.com/watch?v=...`;
return [{ json: { ...d, output: helpMsg }}];

const recs = $input.all();
const d = $('Message Analyze').first().json;
if (!recs.length) return [{ json: { ...d, output: 'Henüz geçmiş yok.' }}];
let text = '*📋 Son 5 Analiz:*\n\n';
recs.forEach((r,i)=>{ const f=r.json.fields||r.json; text+=`${i+1}. *${f.title||'-'}* (${f.seviye||'-'})\n${f.video_id ? 'https://youtube.com/watch?v='+f.video_id : ''}\n\n`; });
return [{ json: { ...d, output: text }}];

const d = $input.first().json;
let text = d.output || d.historyMessage || d.helpMessage || 'Tamam.';

if (d.source !== 'telegram') return [{ json: { ...d, response: text }}];

let html = text
  .replace(/\*\*(.*?)\*\*/g, '<b>$1</b>')
  .replace(/\`(.*?)\`/g, '<code>$1</code>')
  .replace(/\n/g, '\n');

if (html.length > 4000) html = html.substring(0,4000)+'...';
return [{ json: { ...d, telegramHtml: html }}];
